3	#include <cstdint>
4	
5	namespace hybrid {
6	
7	enum class AarSize : uint8_t
8	{
9	  Bits32 = 2,
10	  Bits64 = 3,
11	  Bits128 = 4,
12	};
13	
14	constexpr auto regno_csr(uint16_t csr) -> uint16_t { return csr; }
15	constexpr auto regno_gpr(uint16_t i) -> uint16_t { return 0x1000u + i; }
16	constexpr auto regno_fpr(uint16_t i) -> uint16_t { return 0x1020u + i; }
17	
18	constexpr auto access_register_command(uint16_t regno, AarSize size, bool write,
19	                                       bool postexec = false) -> uint32_t
20	{
21	  uint32_t cmd = 0;
22	  cmd |= (uint32_t(size) & 0x7u) << 20;
23	  if (postexec) cmd |= 1u << 18;
24	  cmd |= 1u << 17;
25	  if (write) cmd |= 1u << 16;
26	  cmd |= regno;
27	  return cmd;
28	}
29	
30	}  // namespace hybrid
